
import './App.css';
import QRScanner from './components/QRScanner';
import isURL from 'is-url';
import favicon from './images/touch/favicon.ico';

function App() {

  const showNotification = (code) => {
      const notifTitle = "QR Code:";
      const notifBody = code;
      const options = {
          body: notifBody,
          icon: favicon
      }
      const notif = new Notification(notifTitle, options);
      setTimeout(() => {
        console.log("Cerrando notificación...");
        notif.close();
      }, 3000); 
  };

  return (
    <div className="App">
      <button className="btn btn-primary mt-5" onClick={() => showNotification("test")}>
        Enviar Notificación
      </button>
      <QRScanner onDecode={(result) => {
        // if(isURL(result)){
        //   window.open(result, "_blank");
        // }
        Notification.requestPermission()
        .then((permission) => {
          if(permission === 'granted') {
              showNotification(result);
          }
        });
      }}/>
    </div>
  );
}

export default App;
