import React, {useState, useEffect} from 'react';
import '../styles/qr-scanner.css';
import {BrowserQRCodeReader,
    NotFoundException,
    ChecksumException,
    FormatException
} from '@zxing/browser';

/* Para más ejemplos sobre como usar esta librería, ir a
** https://zxing-js.github.io/library/ ,
** https://github.com/zxing-js/library/tree/master/docs/examples/
*/

export default function QRScanner(props){
  const {decodeOnce = true, onDecode = (result) => {}} = {...props};
  const [isDecoding, setIsDecoding] = useState(false);
  const codeReader = new BrowserQRCodeReader();
  const constraints = {
    video: {facingMode: "environment"}
  };

  const clipScanner = () => {
    let scanner = document.getElementById("scanner");
    let rect = document.getElementById("container").getBoundingClientRect();
    scanner.style.clip = `rect(${rect.top}px,${rect.right}px,${rect.bottom}px,${rect.left}px)`;
  }

  const startDecoding = () => {
    let vid = document.getElementById("screen-capture");
    navigator.mediaDevices.getUserMedia(constraints).then((stream) => {
      vid.srcObject = stream;
    });
    vid.play();
    if (decodeOnce) {
      QRDecodeOnce();
    } else {
      QRDecodeContinuously();
    }
  }

  const stopDecoding = () => {
    const videos = document.querySelectorAll("video");
    videos.forEach((video) => {
      video.srcObject.getTracks().forEach((track) => track.stop());
      video.srcObject = null;
    });

    setIsDecoding(false);
    console.log('Reset.')
  }

  window.addEventListener('resize', () => {
    clipScanner();
  });

  useEffect(() => {
    clipScanner();
  }, []);

    return (
  <div className="wrapper">
    <video id="screen-capture" className="video-fill blur"/>
    <video id="scanner" className="video-fill" onPlay={() => setIsDecoding(true)}/>
    <div id="container" style={{opacity: !isDecoding ? "0%" : "100%"}}>
      <div className="custom-scanner"></div>
    </div>

    <div className="app__select-photos" onClick={() => {
      document.getElementById("camera-input").click();
    }}>
      <input type="file" capture="camera" id="camera-input" accept="image/*"/>
    </div>
    <div className="app__qr-scanner" onClick={() => !isDecoding ? startDecoding() : stopDecoding()}/>
  </div>
    );

  function QRDecodeOnce() {
    codeReader.decodeOnceFromConstraints(constraints, "scanner").then((result) => {
      // properly decoded qr code
      processResult(result);
    }).catch((err) => {
      console.error(err);
    })
  }

  function QRDecodeContinuously() {
    codeReader.decodeFromConstraints(constraints, "scanner", (result, err) => {
      if (result) {
        // properly decoded qr code
        processResult(result);
      }

      if (err) {
        // As long as this error belongs into one of the following categories
        // the code reader is going to continue as excepted. Any other error
        // will stop the decoding loop.
        //
        // Excepted Exceptions:
        //
        //  - NotFoundException
        //  - ChecksumException
        //  - FormatException

        if (err instanceof NotFoundException) {
          console.log('No QR code found.')
        }

        if (err instanceof ChecksumException) {
          console.log('A code was found, but it\'s read value was not valid.')
        }

        if (err instanceof FormatException) {
          console.log('A code was found, but it was in a invalid format.')
        }
      }
    })
  }

  function processResult(result){
    console.log('Found QR code!', result);
    onDecode(result.text);
    if(decodeOnce) stopDecoding();
  }
}
